-- Insert 49 landmine exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Half-Kneeling One-Arm Landmine Press', 'half-kneeling-one-arm-landmine-press', 'Perform Half-Kneeling One-Arm Landmine Press as a landmine-based push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'BEGINNER', 8, 3, 6, 20, 75, 30, 'Half-Kneeling One-Arm Landmine Press is a landmine exercise for shoulder-friendly unilateral press with trunk and pelvis control. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: upper_body_push_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'One-Handed Pressing', 'capacity', 'upper_body_push_strength', 'landmine_half_kneeling_one_arm_landmine_press', '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing"],"primary_tissues":["shoulder","core","upper_body","triceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"grip_profile":{"type":"one_handed","attachment":"bare_sleeve_or_single_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"press the bar through the angled landmine path while the trunk stays stacked","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve or single handle with one hand; keep the wrist stacked and shoulder packed.","Stack ribs over pelvis, brace gently, and choose a range the shoulder can own."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout."]}'::jsonb),
  ('Tall-Kneeling One-Arm Landmine Press', 'tall-kneeling-one-arm-landmine-press', 'Perform Tall-Kneeling One-Arm Landmine Press as a landmine-based push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'BEGINNER', 8, 3, 6, 20, 75, 30, 'Tall-Kneeling One-Arm Landmine Press is a landmine exercise for overhead-ish press that removes leg drive and exposes rib flare. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: upper_body_push_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'One-Handed Pressing', 'capacity', 'upper_body_push_strength', 'landmine_tall_kneeling_one_arm_landmine_press', '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing"],"primary_tissues":["shoulder","core","upper_body","triceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"grip_profile":{"type":"one_handed","attachment":"bare_sleeve_or_single_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"press the bar through the angled landmine path while the trunk stays stacked","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve or single handle with one hand; keep the wrist stacked and shoulder packed.","Stack ribs over pelvis, brace gently, and choose a range the shoulder can own."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout."]}'::jsonb),
  ('Split-Stance One-Arm Landmine Press', 'split-stance-one-arm-landmine-press', 'Perform Split-Stance One-Arm Landmine Press as a landmine-based push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'BEGINNER', 8, 3, 6, 20, 75, 30, 'Split-Stance One-Arm Landmine Press is a landmine exercise for staggered-stance press for trunk stiffness and hip-to-hand force transfer. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: upper_body_push_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'One-Handed Pressing', 'capacity', 'upper_body_push_strength', 'landmine_split_stance_one_arm_landmine_press', '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing"],"primary_tissues":["shoulder","core","upper_body","triceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"grip_profile":{"type":"one_handed","attachment":"bare_sleeve_or_single_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"press the bar through the angled landmine path while the trunk stays stacked","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve or single handle with one hand; keep the wrist stacked and shoulder packed.","Stack ribs over pelvis, brace gently, and choose a range the shoulder can own."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout."]}'::jsonb),
  ('Square-Stance One-Arm Landmine Press', 'square-stance-one-arm-landmine-press', 'Perform Square-Stance One-Arm Landmine Press as a landmine-based push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'BEGINNER', 8, 3, 6, 20, 75, 30, 'Square-Stance One-Arm Landmine Press is a landmine exercise for general one-arm landmine press with simple athletic stance bracing. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: upper_body_push_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'One-Handed Pressing', 'capacity', 'upper_body_push_strength', 'landmine_square_stance_one_arm_landmine_press', '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing"],"primary_tissues":["shoulder","core","upper_body","triceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"grip_profile":{"type":"one_handed","attachment":"bare_sleeve_or_single_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"press the bar through the angled landmine path while the trunk stays stacked","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve or single handle with one hand; keep the wrist stacked and shoulder packed.","Stack ribs over pelvis, brace gently, and choose a range the shoulder can own."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout."]}'::jsonb),
  ('One-Arm Landmine Push Press', 'one-arm-landmine-push-press', 'Perform One-Arm Landmine Push Press as a landmine-based push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'INTERMEDIATE', 8, 4, 5, 20, 90, 30, 'One-Arm Landmine Push Press is a landmine exercise for leg-drive assisted press for rate of force expression through the landmine arc. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: jump_throw_explosive_power. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'One-Handed Pressing', 'output', 'jump_throw_explosive_power', 'landmine_one_arm_landmine_push_press', '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing"],"primary_tissues":["shoulder","core","upper_body","triceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"high","impact_level":1,"grip_profile":{"type":"one_handed","attachment":"bare_sleeve_or_single_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"press the bar through the angled landmine path while the trunk stays stacked","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve or single handle with one hand; keep the wrist stacked and shoulder packed.","Stack ribs over pelvis, brace gently, and choose a range the shoulder can own."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Reset fully between reps so each rep is fast, crisp, and technically repeatable."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout."]}'::jsonb),
