  ('Landmine Handle-Grip Deadlift', 'landmine-handle-grip-deadlift', 'Perform Landmine Handle-Grip Deadlift as a landmine-based hinge pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'BEGINNER', 8, 3, 6, 20, 75, 30, 'Landmine Handle-Grip Deadlift is a landmine exercise for handle-grip landmine deadlift for hips, trunk, and grip with easy setup and exit. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: hinge_posterior_chain_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'Ball-Grip and Handle-Grip Specialty', 'capacity', 'hinge_posterior_chain_strength', 'landmine_landmine_handle_grip_deadlift', '{"primary_joint_actions":["hip_hinge","posterior_chain_tension","spinal_bracing","grip_closure","wrist_neutral_control"],"primary_tissues":["forearm","hip","core","hamstring","hand"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"high","impact_level":0,"grip_profile":{"type":"handle_grip","attachment":"deadlift_handle_or_v_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"hinge around the hips while the landmine load stays close and the spine remains organized","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Hinge to the working height while keeping the spine long and the bar close enough to control."],"execution_steps":["Push hips back, keep lats and trunk engaged, and stop before spinal position changes.","Extend through the hips rather than pulling the bar with the low back.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Hips back, ribs down.","Feel hamstrings before load.","Grip organizes the shoulder.","Wrist neutral."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb),
  ('Landmine Handle-Grip Split Squat', 'landmine-handle-grip-split-squat', 'Perform Landmine Handle-Grip Split Squat as a landmine-based lunge pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'INTERMEDIATE', 8, 3, 6, 20, 75, 30, 'Landmine Handle-Grip Split Squat is a landmine exercise for handle-grip unilateral strength option with cleaner wrist position and repeatable load path. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: squat_knee_dominant_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'Ball-Grip and Handle-Grip Specialty', 'capacity', 'squat_knee_dominant_strength', 'landmine_landmine_handle_grip_split_squat', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","grip_closure","wrist_neutral_control"],"primary_tissues":["forearm","hip","hand","knee","wrist"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"dynamic","coordination_demand":"high","impact_level":0,"grip_profile":{"type":"handle_grip","attachment":"neutral_handle_attachment","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"use a split or step stance to load one leg while the landmine creates an anterior bracing demand","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Set the split or reverse-lunge stance before adding speed or load."],"execution_steps":["Load the working leg, keep the pelvis level, and avoid collapsing into the front hip or knee.","Drive back to the start position while the bar follows the same arc each rep.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Push the floor away.","Knee tracks over the foot.","Grip organizes the shoulder.","Wrist neutral."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Knee collapse or pelvis shift under load.","Depth chasing after bracing is lost.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb),
  ('Landmine Handle-Grip Rotational Row', 'landmine-handle-grip-rotational-row', 'Perform Landmine Handle-Grip Rotational Row as a landmine-based pull rotate pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.', 'INTERMEDIATE', 8, 3, 6, 20, 75, 30, 'Landmine Handle-Grip Rotational Row is a landmine exercise for rotational row with handle grip for lats, trunk, hip turn, and grip strength. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.', 'Primary subrole: upper_body_pull_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.', 'Own the position first, move the bar second, and stop before the shape changes.', 'Ball-Grip and Handle-Grip Specialty', 'capacity', 'pull_hang_grip_strength', 'landmine_landmine_handle_grip_rotational_row', '{"primary_joint_actions":["scapular_retraction_depression","shoulder_extension","elbow_flexion","hip_hinge_hold","hip_rotation","thoracic_rotation","foot_pivot","grip_closure","wrist_neutral_control"],"primary_tissues":["core","forearm","upper_back","hand","hip"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"dynamic","coordination_demand":"high","impact_level":0,"grip_profile":{"type":"handle_grip","attachment":"neutral_handle_or_rotating_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb, '{"movement_description":"row the landmine while allowing controlled hip rotation without losing trunk stiffness","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Hinge to the working height while keeping the spine long and the bar close enough to control."],"execution_steps":["Pull the sleeve or handle toward the target line while the shoulder blade moves cleanly.","Lower under control until the arm is long but the shoulder is not dumped forward.","Initiate rotation from the hips, pivot the feet, and let the trunk and press follow.","Control the return path instead of letting the bar pull the spine or shoulder.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Row with the back, not the neck.","Long arm down, strong shoulder back.","Hips start it.","Pivot the feet.","Rotate through the hips, not the low back."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Yanking with the neck and upper trap.","Losing hinge position to finish the row.","Twisting through the low back instead of pivoting.","Locking the feet while forcing rotation.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

