-- Landmine library validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'landmine_exercise_library_readiness',
  NULL,
  'Landmine exercise library without conditioning drift or wrong phase intent',
  'Landmine pressing, rowing, squatting, hinging, and rotating must stay quality-first — progressive load for Capacity, fresh intent for Output, calm control for Resilience, not fatigue circuits or HIIT misuse.',
  'Build a coachable landmine exercise library covering one-handed, two-handed, ball-grip, and handle-grip variations for strength, power, trunk control, pulling, lower-body loading, and grip-specific athletic transfer.',
  'The fixed angled bar path enables scalable loading, rotational transfer, trunk bracing, and manageable shoulder demands when dosed correctly.',
  'Landmine work is quality-first. Pressing, rowing, squatting, hinging, and rotating should stay repeatable. Output variations require freshness, low volume, and full recovery; Capacity variations use progressive load without conditioning drift; Resilience variations use bracing and control without threat or fatigue chasing.',
  'Do not overload before owning the arc, rush eccentrics, twist through the low back, or turn landmine work into a conditioning station.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
